import{_ as a,o as e,c as n,ag as l}from"./chunks/framework.DXGyWiRo.js";const D=JSON.parse('{"title":"Capabilities","description":"","frontmatter":{},"headers":[],"relativePath":"capabilities.md","filePath":"capabilities.md"}'),t={name:"capabilities.md"};function o(p,s,i,r,c,y){return e(),n("div",null,[...s[0]||(s[0]=[l(`<h1 id="capabilities" tabindex="-1">Capabilities <a class="header-anchor" href="#capabilities" aria-label="Permalink to &quot;Capabilities&quot;">​</a></h1><p>LinkedQL collapses the traditional data stack — database, API layer, and sync engine — into a single SQL primitive that drops directly into your application.</p><p>This page breaks that system down into its core capabilities:</p><ul><li><strong>At the language level</strong>: LinkedQL&#39;s richer syntax for relationships, structure, and more</li><li><strong>At the system level</strong>: live queries, streaming, changefeed, and more</li><li><strong>At the integration and architecture level</strong>: cross-runtime, local-first, offline-first architectures</li></ul><h2 id="at-a-glance" tabindex="-1">At a Glance <a class="header-anchor" href="#at-a-glance" aria-label="Permalink to &quot;At a Glance&quot;">​</a></h2><p>Ahead of the sections below, here&#39;s your map to the capability pages.</p><p>For language-level capabilities:</p><ul><li><a href="/capabilities/deeprefs">DeepRefs</a></li><li><a href="/capabilities/json-literals">JSON Literals</a></li><li><a href="/capabilities/upsert">UPSERT</a></li></ul><p>For runtime-level capabilities:</p><ul><li><a href="/capabilities/live-queries">Live Queries</a></li><li><a href="/capabilities/streaming">Streaming</a></li><li><a href="/capabilities/changefeeds">Changefeeds</a></li></ul><p>For runtime &amp; distribution:</p><ul><li><a href="/flashql">FlashQL</a></li><li><a href="/flashql/federation-and-sync">Federation, Materialization, and Sync</a></li><li><a href="/docs/integration-patterns">LinkedQL Integration Patterns</a></li></ul><h2 id="language-capabilities" tabindex="-1">Language Capabilities <a class="header-anchor" href="#language-capabilities" aria-label="Permalink to &quot;Language Capabilities&quot;">​</a></h2><p>LinkedQL brings structure and relationships directly into SQL.</p><p>Instead of flattening data and reshaping it in application code, you express the final structure directly in the query.</p><h3 id="meet-json-literals-inline-structuring" tabindex="-1">Meet JSON Literals (Inline Structuring) <a class="header-anchor" href="#meet-json-literals-inline-structuring" aria-label="Permalink to &quot;Meet JSON Literals (Inline Structuring)&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT</span></span>
<span class="line"><span style="color:#C3E88D;">    id,</span></span>
<span class="line"><span style="color:#C3E88D;">    { first: first_name, last: last_name } AS name,</span></span>
<span class="line"><span style="color:#C3E88D;">    { email, phone: phone_number } AS contact</span></span>
<span class="line"><span style="color:#C3E88D;">  FROM users</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>No mapping layer. No post-processing.</p><ul><li>the query returns exactly the shape your UI needs</li><li>no <code>map()</code> / <code>reduce()</code> / DTO transformation step</li><li>fewer mismatches between backend and frontend models</li></ul><h3 id="meet-deeprefs-inline-relationships" tabindex="-1">Meet DeepRefs (Inline Relationships) <a class="header-anchor" href="#meet-deeprefs-inline-relationships" aria-label="Permalink to &quot;Meet DeepRefs (Inline Relationships)&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> posts </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT</span></span>
<span class="line"><span style="color:#C3E88D;">    title,</span></span>
<span class="line"><span style="color:#C3E88D;">    author ~&gt; {</span></span>
<span class="line"><span style="color:#C3E88D;">      id,</span></span>
<span class="line"><span style="color:#C3E88D;">      name,</span></span>
<span class="line"><span style="color:#C3E88D;">      profile ~&gt; { avatar_url }</span></span>
<span class="line"><span style="color:#C3E88D;">    } AS author</span></span>
<span class="line"><span style="color:#C3E88D;">  FROM posts</span></span>
<span class="line"><span style="color:#C3E88D;">  WHERE published = true</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>No need for an ORM or manual JOIN logic.</p><p>If you&#39;ve defined foreign key relationships in your tables, you can traverse them directly.</p><p>The above expresses the data the way the application already understands it:</p><ul><li>a post has an author</li><li>an author has a profile</li></ul><h3 id="documentation" tabindex="-1">Documentation <a class="header-anchor" href="#documentation" aria-label="Permalink to &quot;Documentation&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Capability</th><th style="text-align:left;">What It Adds</th><th style="text-align:left;">Docs</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>DeepRefs</strong></td><td style="text-align:left;">Direct relationship traversal in SQL</td><td style="text-align:left;"><a href="/capabilities/deeprefs">DeepRefs</a></td></tr><tr><td style="text-align:left;"><strong>JSON Literals</strong></td><td style="text-align:left;">Direct structuring in SQL</td><td style="text-align:left;"><a href="/capabilities/json-literals">JSON Literals</a></td></tr><tr><td style="text-align:left;"><strong>UPSERT</strong></td><td style="text-align:left;">A direct UPSERT statement in SQL</td><td style="text-align:left;"><a href="/capabilities/upsert">UPSERT</a></td></tr></tbody></table><hr><h2 id="execution-capabilities" tabindex="-1">Execution Capabilities <a class="header-anchor" href="#execution-capabilities" aria-label="Permalink to &quot;Execution Capabilities&quot;">​</a></h2><p>LinkedQL is built to extend what the host database itself can do—without requiring database-specific extensions.</p><p>On any given database, LinkedQL lets you have live queries as a first-class capability, and directly supports streaming and table-level subscriptions.</p><h3 id="meet-live-queries" tabindex="-1">Meet Live Queries <a class="header-anchor" href="#meet-live-queries" aria-label="Permalink to &quot;Meet Live Queries&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT</span></span>
<span class="line"><span style="color:#C3E88D;">    p.title,</span></span>
<span class="line"><span style="color:#C3E88D;">    p.category,</span></span>
<span class="line"><span style="color:#C3E88D;">    author ~&gt; { name, email } AS author</span></span>
<span class="line"><span style="color:#C3E88D;">  FROM posts AS p</span></span>
<span class="line"><span style="color:#C3E88D;">  WHERE p.published = true</span></span>
<span class="line"><span style="color:#C3E88D;">  ORDER BY p.created_at DESC</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#89DDFF;">,</span><span style="color:#89DDFF;"> {</span><span style="color:#F07178;"> live</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;"> }</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>No need for dedicated GraphQL servers in front of your database. Your query is the subscription.</p><p><code>result</code> is the same shape as a regular query result but self-updating as the database changes over time.</p><p>Updates are pushed from the database to the client—no polling, no manual subscriptions:</p><ul><li>automatically stays current over time</li><li>directly powers reactivity across the app</li></ul><h3 id="meet-changefeeds-direct-table-level-subscriptions" tabindex="-1">Meet Changefeeds (Direct Table-Level Subscriptions) <a class="header-anchor" href="#meet-changefeeds-direct-table-level-subscriptions" aria-label="Permalink to &quot;Meet Changefeeds (Direct Table-Level Subscriptions)&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> unsubscribe </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">wal</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">subscribe</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> public</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> [</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">users</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">] </span><span style="color:#89DDFF;">},</span><span style="color:#89DDFF;"> (</span><span style="color:#BABED8;font-style:italic;">commit</span><span style="color:#89DDFF;">)</span><span style="color:#C792EA;"> =&gt;</span><span style="color:#89DDFF;"> {</span></span>
<span class="line"><span style="color:#BABED8;">  console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#F07178;">(</span><span style="color:#BABED8;">commit</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>Sometimes, table-level changes are the target.</p><p><code>db.wal.subscribe()</code> exposes commit-level events from the underlying database change streams:</p><ul><li>PostgreSQL&#39;s Write Ahead Log (WAL)</li><li>MySQL/MariaDB&#39;s Binary Log (Binlog)</li><li>FlashQL&#39;s Write Ahead Log (WAL)</li></ul><p>It&#39;s especially useful for replication flows, synchronization logic, and downstream processors.</p><h3 id="documentation-1" tabindex="-1">Documentation <a class="header-anchor" href="#documentation-1" aria-label="Permalink to &quot;Documentation&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Capability</th><th style="text-align:left;">What It Adds</th><th style="text-align:left;">Docs</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Live Queries</strong></td><td style="text-align:left;">Queries that stay current as data changes</td><td style="text-align:left;"><a href="/capabilities/live-queries">Live Queries</a></td></tr><tr><td style="text-align:left;"><strong>Streaming</strong></td><td style="text-align:left;">Incremental row delivery</td><td style="text-align:left;"><a href="/capabilities/streaming">Streaming</a></td></tr><tr><td style="text-align:left;"><strong>Changefeeds</strong></td><td style="text-align:left;">Commit-level event streams</td><td style="text-align:left;"><a href="/capabilities/changefeeds">Changefeeds</a></td></tr></tbody></table><hr><h2 id="integration-architecture-and-sync" tabindex="-1">Integration, Architecture, and Sync <a class="header-anchor" href="#integration-architecture-and-sync" aria-label="Permalink to &quot;Integration, Architecture, and Sync&quot;">​</a></h2><p>LinkedQL extends SQL beyond a single runtime.</p><p>Queries can run locally, remotely, or across both — while preserving the same interface.</p><p>Applications that span network and protocol boundaries get a single interface to:</p><ul><li>run a database locally (in the browser, worker, edge)</li><li>connect to upstream databases across boundaries</li><li>federate and synchronize state across nodes</li></ul><p>The application keeps the same <code>db.query()</code> contract in all cases—regardless of where it runs.</p><h3 id="meet-flashql" tabindex="-1">Meet FlashQL <a class="header-anchor" href="#meet-flashql" aria-label="Permalink to &quot;Meet FlashQL&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> FlashQL</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@linked-db/linked-ql/flashql</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  CREATE TABLE public.users (</span></span>
<span class="line"><span style="color:#C3E88D;">    id INT PRIMARY KEY,</span></span>
<span class="line"><span style="color:#C3E88D;">    name TEXT</span></span>
<span class="line"><span style="color:#C3E88D;">  );</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C3E88D;">  INSERT INTO public.users (id, name)</span></span>
<span class="line"><span style="color:#C3E88D;">  VALUES (1, &#39;Ada&#39;), (2, &#39;Linus&#39;);</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT id, name</span></span>
<span class="line"><span style="color:#C3E88D;">  FROM public.users</span></span>
<span class="line"><span style="color:#C3E88D;">  ORDER BY id</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">rows)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// [{ id: 1, name: &#39;Ada&#39; }, { id: 2, name: &#39;Linus&#39; }]</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">disconnect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>Spin up a FlashQL instance in any JavaScript runtime: the browser, the edge, or a worker.</p><p><code>FlashQL</code> brings the full relational engine into the application runtime, powering:</p><ul><li>local-first and offline-first architectures</li><li>data federation and sync across local/remote boundaries</li></ul><p>FlashQL runs a transaction-first, Multi-Version Concurrency Control architecture (MVCC)—like PostgreSQL.</p><h3 id="meet-the-edgeclient" tabindex="-1">Meet the EdgeClient <a class="header-anchor" href="#meet-the-edgeclient" aria-label="Permalink to &quot;Meet the EdgeClient&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> EdgeClient</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@linked-db/linked-ql/edge</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> EdgeClient</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">  url</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">/api/db</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  type</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">http</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT id, name</span></span>
<span class="line"><span style="color:#C3E88D;">  FROM public.users</span></span>
<span class="line"><span style="color:#C3E88D;">  ORDER BY id</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p><code>EdgeClient</code> preserves the LinkedQL contract across runtime boundaries.</p><p>The data lives in a remote runtime, but your application sees the same SQL interface—no change in how queries are written or consumed:</p><ul><li>live queries</li><li>inline relationships</li><li>sync, etc.</li></ul><h3 id="meet-federation-and-sync" tabindex="-1">Meet Federation and Sync <a class="header-anchor" href="#meet-federation-and-sync" aria-label="Permalink to &quot;Meet Federation and Sync&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> FlashQL</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@linked-db/linked-ql/flashql</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> EdgeClient</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@linked-db/linked-ql/edge</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#82AAFF;">  getUpstreamClient</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> ()</span><span style="color:#C792EA;"> =&gt;</span></span>
<span class="line"><span style="color:#89DDFF;">    new</span><span style="color:#82AAFF;"> EdgeClient</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> url</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">/api/db</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span><span style="color:#F07178;"> type</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">http</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;"> }</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  CREATE REALTIME VIEW store.orders AS</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT * FROM public.orders</span></span>
<span class="line"><span style="color:#C3E88D;">  WITH (replication_origin = &#39;postgres://db.url.com&#39;)</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>FlashQL takes you beyond local storage to tie in any number of upstream data sources.</p><p>The realtime view above behaves like a local table:</p><ul><li>queries read from local state</li><li>updates are applied asynchronously from upstream</li><li>writes can be synchronized back upstream</li></ul><p>You keep one SQL surface for reads and writes, plus gain:</p><ul><li>federation across runtime and network boundaries</li><li>local retention and offline reads</li><li>automatic inbound sync through the realtime view</li></ul><h3 id="documentation-2" tabindex="-1">Documentation <a class="header-anchor" href="#documentation-2" aria-label="Permalink to &quot;Documentation&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Capability</th><th style="text-align:left;">What It Adds</th><th style="text-align:left;">Docs</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>FlashQL</strong></td><td style="text-align:left;">Embedded SQL runtime</td><td style="text-align:left;"><a href="/flashql">FlashQL</a></td></tr><tr><td style="text-align:left;"><strong>Federation, Materialization, and Sync</strong></td><td style="text-align:left;">Queries spanning local and remote data</td><td style="text-align:left;"><a href="/flashql/federation-and-sync">Federation, Materialization, and Sync</a></td></tr><tr><td style="text-align:left;"><strong>LinkedQL Integration Patterns</strong></td><td style="text-align:left;">One database contract across boundaries</td><td style="text-align:left;"><a href="/docs/integration-patterns">LinkedQL Integration Patterns</a></td></tr></tbody></table>`,72)])])}const F=a(t,[["render",o]]);export{D as __pageData,F as default};
